// ── RBA / IronPlanet Email Parser ─────────────────────────────────
// Handles: saved-search digest emails, price-drop alerts, lot alerts
// Strategies applied in order:
//   1. Anchor-tag scan: find listing URLs → extract title + price from context
//   2. Fallback: whole-email single-listing (short price-drop alerts)

const html   = $input.item.json.html   || $input.item.json.text || '';
const subject = ($input.item.json.subject || '').trim();
const emailId = $input.item.json.id || String(Date.now());
const today   = new Date().toISOString().slice(0, 10);

// HTML entity decoder
const decode = (s) => (s || '')
  .replace(/&amp;/g,  '&').replace(/&lt;/g,  '<').replace(/&gt;/g,  '>')
  .replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/&nbsp;/g, ' ')
  .replace(/&#\d+;/g, '').replace(/\s+/g, ' ').trim();

const seen    = new Set();
const results = [];

// ── Strategy 1: anchor-tag extraction ─────────────────────────────
if (html.length > 50) {
  // Match <a href="...(rbauction|ironplanet)...DIGITS...">...</a>
  const anchorRe = /<a\b[^>]+href=["']([^"']*(?:rbauction\.com|ironplanet\.com)[^"']*)(["'][^>]*)>((?:[\s\S](?!<\/a>))*[\s\S]?)<\/a>/gi;
  let m;

  while ((m = anchorRe.exec(html)) !== null) {
    const rawUrl     = decode(m[1]);
    const anchorHtml = m[3] || '';
    const anchorText = decode(anchorHtml.replace(/<[^>]+>/g, ' '));

    // Skip navigation / footer links
    if (/\/(search|home|register|login|help|about|contact|unsubscribe|category|rss|privacy|terms)\b/i.test(rawUrl)) continue;
    // Require anchor text that looks like an equipment title
    const isEquip = /\b(19|20)\d{2}\b|\b(bucket|thumb|ripper|auger|coupler|breaker|excavator|attachment|compactor|grapple|hammer|blade|dozer|loader|skid|track)\b/i.test(anchorText);
    if (!isEquip || anchorText.length < 8) continue;

    // Canonical URL (strip tracking params)
    const cleanUrl = rawUrl.split('?')[0];
    if (seen.has(cleanUrl)) continue;
    seen.add(cleanUrl);

    // Context window around the anchor for price / location extraction
    const ctxStart = Math.max(0, m.index - 400);
    const ctxEnd   = Math.min(html.length, m.index + m[0].length + 800);
    const ctxText  = html.slice(ctxStart, ctxEnd).replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ');

    // Price extraction — ordered by specificity
    const pricePatterns = [
      /Sold\s+(?:for|price)[^\d]{0,10}(?:CAD|USD|C)?\$?\s*([\d,]+(?:\.\d{2})?)/i,
      /Final\s+(?:bid|price)[^\d]{0,10}\$?\s*([\d,]+(?:\.\d{2})?)/i,
      /(?:CAD|CDN)\$?\s*([\d,]+(?:\.\d{2})?)/i,
      /\$\s*([\d,]+(?:\.\d{2})?)\s*(?:CAD|CDN)/i,
      /Current\s+(?:bid|price)[^\d]{0,10}\$?\s*([\d,]+(?:\.\d{2})?)/i,
      /Opening\s+bid[^\d]{0,10}\$?\s*([\d,]+(?:\.\d{2})?)/i,
      /Estimate[^\d]{0,10}\$?\s*([\d,]+(?:\.\d{2})?)/i,
      /\$\s*([\d,]{3,}(?:\.\d{2})?)/
    ];

    let price_cad = 0;
    for (const pat of pricePatterns) {
      const pm = ctxText.match(pat);
      if (pm) {
        const p = parseFloat(pm[1].replace(/,/g, ''));
        if (p >= 50 && p <= 2000000) { price_cad = p; break; }
      }
    }
    if (price_cad === 0) continue;

    // Listing ID — prefer numeric segment from URL, fall back to hash
    const numericId = rawUrl.match(/\/(\d{6,12})(?:\/|\?|$)/);
    const listing_id = numericId
      ? `RBA-${numericId[1]}`
      : `RBA-${cleanUrl.replace(/[^a-zA-Z0-9]/g, '').slice(-32)}`;

    // Location extraction
    const locMatch = ctxText.match(/(?:Location|Lot\s+Location)[:\s]+([A-Za-z][A-Za-z ,]{2,48})(?:\s{2,}|\|[^|]|$)/i);
    const location = locMatch ? locMatch[1].trim().slice(0, 100) : undefined;

    results.push({
      json: {
        listing_id,
        title:        anchorText.slice(0, 255),
        price_cad,
        sale_date:    today,
        category_raw: 'email-rba',
        url:          rawUrl.slice(0, 500),
        ...(location ? { location } : {})
      }
    });

    if (results.length >= 50) break;
  }
}

// ── Strategy 2: whole-email fallback ──────────────────────────────
if (results.length === 0 && html.length > 20) {
  const bodyText = html.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ');
  const priceMatch = bodyText.match(/(?:CAD|CDN)?\$\s*([\d,]+(?:\.\d{2})?)/);
  const price = priceMatch ? parseFloat(priceMatch[1].replace(/,/g, '')) : 0;

  if (price >= 50 && price <= 2000000 && subject.length >= 5) {
    results.push({
      json: {
        listing_id:   `RBA-EMAIL-${emailId}`,
        title:        subject.slice(0, 255),
        price_cad:    price,
        sale_date:    today,
        category_raw: 'email-fallback',
        url:          ''
      }
    });
  }
}

return results;

const listings = $input.item.json.listings || [];
if (listings.length === 0) return [];

listings.sort((a, b) => (a.price_cad || 0) - (b.price_cad || 0));

const fmt = (n) => new Intl.NumberFormat('en-CA', {
  style: 'currency', currency: 'CAD', maximumFractionDigits: 0
}).format(n);

const lines = listings.map((l, i) => {
  const cls = l.classification || {};
  const clsStr = cls.category
    ? `${cls.category}${cls.tonnage_class ? ' · ' + cls.tonnage_class : ''}${cls.brand ? ' · ' + cls.brand : ''}`
    : '';
  return [
    `*${i + 1}. ${(l.title || '').slice(0, 90)}*`,
    `💰 ${fmt(l.price_cad || 0)}` + (l.location ? `  📍 ${l.location}` : ''),
    clsStr ? `🤖 ${clsStr}${cls.needs_review ? ' ⚠️' : ''}` : '',
    l.url ? `🔗 [Listing](${l.url})` : ''
  ].filter(Boolean).join('\n');
}).join('\n\n───\n\n');

const msg = `🏷 *RBA/IronPlanet — ${listings.length} 条新拍卖情报*\n\n${lines}\n\n📊 [Intel Dashboard](https://freightracing.ca/intel) · _WF6_`;
return [{ json: { message: msg, count: listings.length } }];
